import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import { useCart } from '../context/CartContext';

const Home = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const { addToCart } = useCart();

  useEffect(() => {
    api.get('/products')
      .then((res) => { setProducts(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return (
    <p style={{ textAlign: 'center', marginTop: '40px' }}>Loading products...</p>
  );

  return (
    <div style={{ padding: '24px' }}>
      <h2 style={{ marginBottom: '20px' }}>🛍️ All Products</h2>
      {products.length === 0 && (
        <p>No products yet. Add some from the Admin panel!</p>
      )}
      <div style={styles.grid}>
        {products.map((p) => (
          <div key={p._id} style={styles.card}>
            <img src={p.image} alt={p.name} style={styles.img} />
            <h3 style={{ margin: '10px 0 4px' }}>{p.name}</h3>
            <p style={{ color: '#888', fontSize: '13px' }}>{p.category}</p>
            <p style={{ fontWeight: 'bold', color: '#e94560' }}>${p.price}</p>
            <div style={{ display: 'flex', gap: '8px', marginTop: '10px' }}>
              <Link to={`/product/${p._id}`} style={styles.detailBtn}>View</Link>
              <button onClick={() => addToCart(p)} style={styles.cartBtn}>
                Add to Cart
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
  grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(230px, 1fr))', gap: '20px' },
  card: { border: '1px solid #eee', borderRadius: '10px', padding: '16px', boxShadow: '0 2px 8px rgba(0,0,0,0.07)', background: '#fff' },
  img: { width: '100%', height: '180px', objectFit: 'cover', borderRadius: '8px' },
  detailBtn: {
    flex: 1, textAlign: 'center', padding: '8px', background: '#1a1a2e',
    color: '#fff', borderRadius: '6px', textDecoration: 'none', fontSize: '14px',
  },
  cartBtn: {
    flex: 1, padding: '8px', background: '#e94560', color: '#fff',
    border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '14px',
  },
};

export default Home;
